// Берём данные формы из Transform Data
const form = $('Transform Data').first().json;

// Пробуем получить контент сайта (если пришли из ветки Firecrawl)
let siteContent = 'Сайт клиента не указан или недоступен для анализа.';
try {
  const input = $input.first().json;
  if (input && input.data && input.data.markdown) {
    siteContent = input.data.markdown.substring(0, 4000);
  }
} catch(e) {}

// Формируем ИНН-слаг (если нет ИНН — используем timestamp)
const inn = (form.inn && form.inn.trim().length > 5)
  ? form.inn.trim()
  : Date.now().toString();

// Формируем промпт для AI
const prompt = `Ты — старший аналитик по цифровому маркетингу и автоматизации бизнеса в России. Твоя задача — сделать честный, конкретный и полезный аудит.

ДАННЫЕ КОМПАНИИ:
- Название: ${form.company || 'не указано'}
- Ниша / сфера: ${form.industry || 'не указана'}
- Город: ${form.city || 'не указан'}
- Возраст бизнеса: ${form.business_age || 'не указан'}
- Сайт: ${form.site || 'не указан'}
- VK: ${form.vk || 'нет'}
- Telegram: ${form.telegram || 'нет'}
- Instagram: ${form.instagram || 'нет'}
- Яндекс Карты: ${form.yandex || 'нет'}
- Avito: ${form.avito || 'нет'}
- Проблемы (слова клиента): ${form.problems || 'не указаны'}
- Цели бизнеса: ${form.goals || 'не указаны'}
- Видение автоматизации: ${form.automation_vision || 'не указано'}

АНАЛИЗ САЙТА:
${siteContent}

Верни ТОЛЬКО валидный JSON без markdown-блоков, без пояснений:
{
  "company": "${form.company || 'Компания'}",
  "industry": "${form.industry || 'Бизнес'}",
  "city": "${form.city || ''}",
  "score": <число 0-100, общий индекс цифровизации>,
  "metrics": {
    "site": <0-100>,
    "social": <0-100>,
    "automation": <0-100>,
    "crm": <0-100>,
    "marketing": <0-100>
  },
  "problems": ["конкретная проблема 1", "конкретная проблема 2", "конкретная проблема 3"],
  "opportunities": ["возможность роста 1", "возможность роста 2", "возможность роста 3"],
  "lost_audience": {
    "vk": "X 000",
    "telegram": "X 000",
    "search": "X 000"
  },
  "roi": {
    "leads": "+X%",
    "profit": "XXX 000 ₽/мес",
    "time": "XX ч/мес"
  },
  "forecast": {
    "leads": "×X",
    "profit": "+X%",
    "time_saved": "X%"
  },
  "competitors": {
    "social": "описание активности конкурентов",
    "automation": "описание автоматизации у конкурентов",
    "response_time": "< X мин"
  },
  "response_time": "текущее время ответа клиента",
  "roadmap": [
    "Неделя 1: ...",
    "Неделя 2: ...",
    "Неделя 3: ...",
    "Неделя 4: ..."
  ]
}`;

return {
  prompt: prompt,
  inn: inn,
  form: form
};

const aiResponse = $input.first().json;
const promptData = $('Prepare AI Prompt').first().json;
const form = promptData.form;
const inn = promptData.inn;

let auditData;
try {
  const content = aiResponse.choices[0].message.content;
  // Убираем markdown-обёртку если AI вернул с ней
  const cleaned = content
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/gi, '')
    .trim();
  auditData = JSON.parse(cleaned);
} catch(e) {
  // Fallback если AI вернул невалидный JSON
  auditData = {
    company: form.company || 'Компания',
    industry: form.industry || 'Бизнес',
    city: form.city || '',
    score: 35,
    metrics: { site: 30, social: 20, automation: 10, crm: 15, marketing: 25 },
    problems: [
      'Нет автоответа на входящие заявки',
      'Соцсети ведутся нерегулярно',
      'Ручная обработка всех обращений'
    ],
    opportunities: [
      'Telegram-бот сократит время ответа до 1 мин',
      'Автопостинг увеличит охват в 3 раза',
      'CRM исключит потерю заявок'
    ],
    lost_audience: { vk: '5 000', telegram: '3 000', search: '2 000' },
    roi: { leads: '+40%', profit: '150 000 ₽/мес', time: '40 ч/мес' },
    forecast: { leads: '×2', profit: '+35%', time_saved: '40%' },
    competitors: {
      social: 'Ведут активно, 1-2 поста в день',
      automation: 'Используют частично',
      response_time: '< 15 мин'
    },
    response_time: '> 2 часов',
    roadmap: [
      'Неделя 1: Настройка Telegram-бота и автоответов',
      'Неделя 2: Подключение CRM и воронки продаж',
      'Неделя 3: Автоматизация соцсетей',
      'Неделя 4: Аналитика и оптимизация'
    ]
  };
}

return {
  inn: inn,
  auditData: auditData,
  auditUrl: `https://neuromedia-nn.ru/audit/${inn}`,
  clientName: form.name || '',
  clientPhone: form.phone || '',
  clientTelegram: form.telegram || ''
};
